import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    # {The new algorithm selects the next customer by balancing the cost using weighted parameters for travel time, time window urgency, customer penalty for being too close to other trucks, and optimizing the route to minimize overlaps between truck paths.}
    best_node = None
    min_weighted_cost = float('inf')

    for i, customer_pos in enumerate(unvisited_customers):
        travel_time = np.linalg.norm(cur_truck_pos - customer_pos) / truck_speed
        arrival_time = current_time + travel_time
        window_start, window_end = time_windows[i]

        if arrival_time > window_end:
            continue

        time_urgency = max(0, 1 - (arrival_time - window_start) / (window_end - window_start + 1e-5))
        proximity_penalty = 0

        for truck_pos in all_truck_pos:
            if not np.array_equal(truck_pos, cur_truck_pos):
                proximity_penalty += max(0, 5 - np.linalg.norm(truck_pos - customer_pos))

        weighted_cost = travel_time + 0.7 * time_urgency + 0.3 * proximity_penalty

        if weighted_cost < min_weighted_cost:
            min_weighted_cost = weighted_cost
            best_node = i

    return best_node
